css:
.loader {color: var(--loader-color, #16a34a);
  --loader-secondary-color: #86efac;
  --loader-bg: #ffffff;
   width: 68px;
   aspect-ratio: 1;
   border: 8px solid currentColor;
   box-sizing: border-box;
   background: radial-gradient(farthest-side at right,currentColor 98%,#0000) 20% 50%/40% 80%, radial-gradient(farthest-side at left ,currentColor 98%,#0000) 80% 50%/40% 80%, currentColor;
   background-repeat: no-repeat;
   filter: blur(4px) contrast(10);
   animation: l18 0.8s infinite alternate;
}
@keyframes l18  {
  0%,20% {background-position:20% 50%,80% 50%}
100% {background-position:80% 50%,20% 50%}
}
